     1→import { createServer } from 'node:http';
     2→import { resolve, isAbsolute } from 'node:path';
     3→import { watch } from 'node:fs';
     4→import { loadConfig } from './config/loader.js';
     5→import { configExists, runSetup } from './config/setup.js';
     6→import { StateStore } from './state/store.js';
     7→import { PipelineManager } from './pipeline/manager.js';
     8→import { createApp } from './web/server.js';
     9→import { attachWebSocket } from './web/ws-handler.js';
    10→
    11→const DEV_MODE = process.env.JIRANIMO_MODE === 'development';
    12→const SELF_MODE = DEV_MODE && process.env.JIRANIMO_SELF === '1';
    13→
    14→async function main() {
    15→  if (DEV_MODE) {
    16→    console.log(`\n[DEV] Running in development mode${SELF_MODE ? ' (self)' : ''}\n`);
    17→  }
    18→
    19→  // Load config — dev uses local file, prod uses global
    20→  let config;
    21→  if (DEV_MODE) {
    22→    const devConfigPath = resolve(process.cwd(), 'jiranimo.dev.config.json');
    23→    config = loadConfig({ configPath: devConfigPath });
    24→    // Self mode: point reposRoot at the parent directory (contains the Jiranimo repo itself)
    25→    if (SELF_MODE) {
    26→      config = { ...config, reposRoot: resolve(process.cwd(), '..'), repoName: 'Jiranimo' };
    27→    } else if (!isAbsolute(config.reposRoot)) {
    28→      // Resolve relative reposRoot against cwd
    29→      config = { ...config, reposRoot: resolve(process.cwd(), config.reposRoot) };
    30→    }
    31→    // Set dev-local paths (self mode gets its own state to avoid conflicts)
    32→    const statePrefix = SELF_MODE ? '.dev-self' : '.dev';
    33→    config.statePath = config.statePath ?? resolve(process.cwd(), `${statePrefix}-state.json`);
    34→    config.logsDir = config.logsDir ?? resolve(process.cwd(), `${statePrefix}-logs`);
    35→  } else {
    36→    if (!configExists()) {
    37→      await runSetup();
    38→    }
    39→    config = loadConfig();
    40→  }
    41→
    42→  // State — dev uses local file, prod uses global default
    43→  const store = new StateStore(config.statePath ? { filePath: config.statePath } : undefined);
    44→  const pipeline = new PipelineManager(store, config);
    45→
    46→  const app = createApp(store, pipeline);
    47→  const server = createServer(app);
    48→  const wsHandler = attachWebSocket(server, pipeline);
    49→
    50→  // In dev mode, watch extension files and broadcast reload signal
    51→  if (DEV_MODE) {
    52→    startExtensionWatcher(wsHandler);
    53→  }
    54→
    55→  server.listen(config.web.port, config.web.host, () => {
    56→    console.log(`Jiranimo server running on http://${config.web.host}:${config.web.port}`);
    57→    console.log(`Dashboard: http://${config.web.host}:${config.web.port}`);
    58→    console.log(`Repos root: ${config.reposRoot}`);
    59→    console.log(`MCP endpoint: http://${config.web.host}:${config.web.port}/mcp`);
    60→
    61→    if (DEV_MODE) {
    62→      console.log(`\n[DEV] Config: ${resolve(process.cwd(), 'jiranimo.dev.config.json')}`);
    63→      console.log(`[DEV] State: ${config.statePath}`);
    64→      console.log(`[DEV] Logs: ${config.logsDir}`);
    65→      console.log(`[DEV] Extension auto-reload: enabled`);
    66→    } else {
    67→      const extensionPath = resolve(process.cwd(), '..', 'extension');
    68→      console.log(`\nTo install the Chrome extension:`);
    69→      console.log(`  1. Open chrome://extensions`);
    70→      console.log(`  2. Enable "Developer mode" (top right)`);
    71→      console.log(`  3. Click "Load unpacked"`);
    72→      console.log(`  4. Select: ${extensionPath}`);
    73→    }
    74→    console.log('');
    75→  });
    76→
    77→  let shuttingDown = false;
    78→  function shutdown() {
    79→    if (shuttingDown) return;
    80→    shuttingDown = true;
    81→    console.log('\nShutting down...');
    82→    store.flushSync();
    83→    store.destroy();
    84→    server.close(() => process.exit(0));
    85→    setTimeout(() => process.exit(0), 2000).unref();
    86→  }
    87→
    88→  process.on('SIGINT', shutdown);
    89→  process.on('SIGTERM', shutdown);
    90→}
    91→
    92→function startExtensionWatcher(wsHandler: ReturnType<typeof attachWebSocket>) {
    93→  const extensionDir = resolve(process.cwd(), '..', 'extension');
    94→  let debounceTimer: ReturnType<typeof setTimeout> | null = null;
    95→
    96→  try {
    97→    watch(extensionDir, { recursive: true }, (_event, filename) => {
    98→      if (!filename || filename.includes('node_modules')) return;
    99→      // Debounce — wait 500ms for batch changes
   100→      if (debounceTimer) clearTimeout(debounceTimer);
   101→      debounceTimer = setTimeout(() => {
   102→        console.log(`[DEV] Extension file changed: ${filename}`);
   103→        wsHandler.send({ type: 'extension-reload' });
   104→      }, 500);
   105→    });
   106→    console.log(`[DEV] Watching extension/ for changes`);
   107→  } catch (err) {
   108→    console.warn(`[DEV] Could not watch extension directory:`, err);
   109→  }
   110→}
   111→
   112→main();
