/* ─── About overlay ──────────────────────────────────────── */

.jiranimo-about-overlay {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(9, 30, 66, 0.54);
  z-index: 10000;
  display: flex;
  align-items: center;
  justify-content: center;
}

.jiranimo-about-modal {
  background: #fff;
  border-radius: 8px;
  padding: 28px 28px 24px;
  width: 460px;
  max-width: 90vw;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 8px 32px rgba(0,0,0,0.3);
  color: #172b4d;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

.jiranimo-about-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
}

.jiranimo-about-title {
  display: flex;
  align-items: center;
  gap: 10px;
}

.jiranimo-about-logo {
  width: 28px;
  height: 28px;
  color: #0052cc;
  flex-shrink: 0;
}

.jiranimo-about-header h2 {
  margin: 0;
  font-size: 22px;
  font-weight: 700;
  color: #172b4d;
}

.jiranimo-about-close {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 22px;
  line-height: 1;
  color: #6b778c;
  padding: 2px 6px;
  border-radius: 4px;
}

.jiranimo-about-close:hover {
  background: #f4f5f7;
  color: #172b4d;
}

.jiranimo-about-tagline {
  margin: 0 0 4px;
  font-size: 14px;
  color: #6b778c;
}

.jiranimo-about-version {
  margin: 0 0 20px;
  font-size: 12px;
  color: #97a0af;
}

.jiranimo-about-section {
  margin-bottom: 20px;
}

.jiranimo-about-section h3 {
  margin: 0 0 10px;
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: #6b778c;
}

.jiranimo-about-section ol,
.jiranimo-about-section ul {
  margin: 0;
  padding-left: 20px;
}

.jiranimo-about-section li {
  font-size: 14px;
  line-height: 1.6;
  color: #172b4d;
  margin-bottom: 4px;
}

.jiranimo-about-states {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.jiranimo-about-state {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 14px;
  color: #172b4d;
}

.jiranimo-about-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.jiranimo-about-dot.idle       { background: #0052cc; }
.jiranimo-about-dot.queued     { background: #ff991f; }
.jiranimo-about-dot.in-progress { background: #0052cc; }
.jiranimo-about-dot.completed  { background: #36b37e; }
.jiranimo-about-dot.failed     { background: #de350b; }

.jiranimo-about-shortcut {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 14px;
  color: #172b4d;
  margin-bottom: 8px;
}

.jiranimo-about-shortcut kbd {
  display: inline-block;
  padding: 3px 8px;
  font-size: 13px;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, monospace;
  background: #f4f5f7;
  border: 1px solid #c1c7d0;
  border-bottom-width: 2px;
  border-radius: 4px;
  color: #172b4d;
  white-space: nowrap;
}

